package main
import "fmt"

type Node struct {
    info int
    next *Node
    prev *Node
}

type DList struct {
    head *Node
}

func NewDList() *DList {
    dlist := DList{}
    dlist.head = &Node{}
    dlist.head.next = dlist.head
    dlist.head.prev = dlist.head

    return &dlist
}

func insert(ref *Node, value int) {
    previous := ref.prev

    new_node := &Node {
        info: value,
        next: ref,
        prev: previous,
    }

    previous.next = new_node
    ref.prev = new_node
}

func (list *DList) PushBack(value int) {
    insert(list.head, value)
}

func (list *DList) PushFront(value int) {
    insert(list.head.next, value)
}

func Mostrando(list *DList) {
    it := list.head.next 

    fmt.Print("[")
    for it = list.head.next; it != list.head; it = it.next {
        fmt.Printf(" %d", it.info)
    }
    fmt.Print(" ]\n")
}

func main(){
    list := NewDList()

    for i := range 10 {
        list.PushBack(i)
    }

    Mostrando(list)


}
